assistantMessages:
I'll help you set a limit buy for ETH at $2,800. Let me walk through what this involves and how to implement it with the MetaMask Agent Wallet skill.

## Understanding the Request

A "limit buy" isn't natively supported by MetaMask itself — it requires interacting with a DEX that supports limit orders (like **1inch Limit Orders**, **CoW Protocol**, or **Uniswap via a limit order aggregator**). The agent will:

1. Check permissions/constraints
2. Navigate to a supported limit order protocol
3. Place a signed limit order (off-chain signature, no gas until filled)
4. Monitor and report status

---

## Implementation

```typescript
// src/actions/limitBuy.ts
import { chromium } from 'playwright';
import { loadConfig } from '../config';
import { TransactionGuard } from '../guard';
import { Logger } from '../logger';
import { getETHPrice } from '../price';

interface LimitOrderParams {
  tokenIn: string;       // e.g. "USDC"
  tokenOut: string;      // e.g. "ETH"
  limitPrice: number;    // USD price trigger, e.g. 2800
  amountIn?: string;     // Amount of tokenIn to spend (optional, uses perTx limit)
  protocol: 'cowswap' | '1inch' | 'uniswap-x';
  chainId: number;
}

// Protocol router addresses for allowlist checking
const PROTOCOL_ADDRESSES: Record<string, Record<number, string>> = {
  cowswap: {
    1:   '0x9008D19f58AAbD9eD0D60971565AA8510560ab41', // CoW Settlement
    100: '0x9008D19f58AAbD9eD0D60971565AA8510560ab41', // Gnosis Chain
  },
  '1inch': {
    1:   '0x119c71D3BbAC22029622cbaEc24854d3D32D2828', // 1inch Limit Order v3
    137: '0x94Bc2a1C732BcAd7343B25af48385Fe76E08734f',
  },
  'uniswap-x': {
    1:   '0x3fC91A3afd70395Cd496C647d5a6CC9D4B2b7FAD', // UniswapX Reactor
  },
};

export async function placeLimitBuy(params: LimitOrderParams): Promise<void> {
  const config = loadConfig();
  const guard  = new TransactionGuard(config);
  const logger = new Logger();

  // ── 1. Validate protocol is on allowlist ──────────────────────────────────
  const routerAddress = PROTOCOL_ADDRESSES[params.protocol]?.[params.chainId];
  if (!routerAddress) {
    throw new Error(
      `Protocol "${params.protocol}" not supported on chain ${params.chainId}`
    );
  }

  const guardCheck = guard.checkProtocol(routerAddress);
  if (!guardCheck.allowed) {
    throw new Error(`Guard blocked: ${guardCheck.reason}`);
  }

  // ── 2. Estimate order size against spend limits ───────────────────────────
  const currentETHPrice = await getETHPrice();
  const spendAmountUSD  = params.amountIn
    ? parseFloat(params.amountIn)          // user-specified USDC amount
    : parseFloat(config.constraints.spendLimit.perTx) / 1e6; // default to perTx cap

  const spendCheck = guard.checkSpend(spendAmountUSD);
  if (!spendCheck.allowed) {
    throw new Error(`Spend limit exceeded: ${spendCheck.reason}`);
  }

  // ── 3. Check if approval is required ─────────────────────────────────────
  const approvalThreshold = parseFloat(config.constraints.requireApproval?.above ?? '0');
  if (spendAmountUSD > approvalThreshold) {
    logger.logApprovalRequired({
      action:      'limit-buy',
      tokenIn:     params.tokenIn,
      tokenOut:    params.tokenOut,
      limitPrice:  params.limitPrice,
      spendAmount: spendAmountUSD,
      protocol:    params.protocol,
    });
    console.log(
      `⚠️  Transaction requires approval:\n` +
      `   Action:      Limit Buy\n` +
      `   Buying:      ETH at $${params.limitPrice}\n` +
      `   Spending:    $${spendAmountUSD} ${params.tokenIn}\n` +
      `   Protocol:    ${params.protocol}\n` +
      `   Current ETH: $${currentETHPrice}\n\n` +
      `   Reply "approve" to continue.`
    );
    return; // Pause — wait for explicit user approval
  }

  // ── 4. Launch browser and place order ────────────────────────────────────
  console.log(`🚀 Placing limit buy: ETH @ $${params.limitPrice} via ${params.protocol}`);

  const browser = await chromium.launchPersistentContext(
    config.browserProfile,
    {
      headless: false,          // visible so MetaMask popups work
      args: [
        `--disable-extensions-except=${config.metamaskPath}`,
        `--load-extension=${config.metamaskPath}`,
      ],
    }
  );

  try {
    const page = await browser.newPage();

    if (params.protocol === 'cowswap') {
      await placeCowSwapLimitOrder(page, params, spendAmountUSD, logger);
    } else if (params.protocol === '1inch') {
      await place1inchLimitOrder(page, params, spendAmountUSD, logger);
    } else {
      throw new Error(`Protocol "${params.protocol}" UI automation not yet implemented`);
    }

  } finally {
    await browser.close();
  }
}

// ── CoW Protocol limit order ──────────────────────────────────────────────────
async function placeCowSwapLimitOrder(
  page: any,
  params: LimitOrderParams,
  spendAmountUSD: number,
  logger: Logger
): Promise<void> {

  await page.goto('https://swap.cow.fi/#/1/limit/USDC/ETH', {
    waitUntil: 'networkidle',
  });

  // Connect wallet (MetaMask popup)
  await page.click('[data-testid="connect-wallet-button"]');
  await page.click('[data-testid="metamask-option"]');
  await handleMetaMaskConnection(page);

  // Switch to Limit tab (CoW defaults to swap)
  await page.click('[data-testid="limit-order-tab"]');
  await page.waitForSelector('[data-testid="limit-price-input"]');

  // Set sell amount (USDC)
  await page.fill('[data-testid="sell-amount-input"]', spendAmountUSD.toString());

  // Set limit price
  await page.fill('[data-testid="limit-price-input"]', params.limitPrice.toString());

  // Confirm calculated ETH amount
  const ethAmount = await page.inputValue('[data-testid="buy-amount-input"]');
  console.log(`   Will receive: ~${ethAmount} ETH if filled`);

  // Set expiry (default 7 days for limit orders)
  await page.click('[data-testid="expiry-selector"]');
