};

export async function placeLimitBuy(params: LimitOrderParams): Promise<void> {
  const config = loadConfig();
  const guard  = new TransactionGuard(config);
  const logger = new Logger();

  // ── 1. Validate protocol is on allowlist ──────────────────────────────────
  const routerAddress = PROTOCOL_ADDRESSES[params.protocol]?.[params.chainId];
  if (!routerAddress) {
    throw new Error(
      `Protocol "${params.protocol}" not supported on chain ${params.chainId}`
    );
  }

  const guardCheck = guard.checkProtocol(routerAddress);
  if (!guardCheck.allowed) {
    throw new Error(`Guard blocked: ${guardCheck.reason}`);
  }

  // ── 2. Estimate order size against spend limits ───────────────────────────
  const currentETHPrice = await getETHPrice();
  const spendAmountUSD  = params.amountIn
    ? parseFloat(params.amountIn)          // user-specified USDC amount
    : parseFloat(config.constraints.spendLimit.perTx) / 1e6; // default to perTx cap

  const spendCheck = guard.checkSpend(spendAmountUSD);
  if (!spendCheck.allowed) {
    throw new Error(`Spend limit exceeded: ${spendCheck.reason}`);
  }

  // ── 3. Check if approval is required ─────────────────────────────────────
  const approvalThreshold = parseFloat(config.constraints.requireApproval?.above ?? '0');
  if (spendAmountUSD > approvalThreshold) {
    logger.logApprovalRequired({
      action:      'limit-buy',
      tokenIn:     params.tokenIn,
      tokenOut:    params.tokenOut,
      limitPrice:  params.limitPrice,
      spendAmount: spendAmountUSD,
      protocol:    params.protocol,
    });
    console.log(
      `⚠️  Transaction requires approval:\n` +
      `   Action:      Limit Buy\n` +
      `   Buying:      ETH at $${params.limitPrice}\n` +
      `   Spending:    $${spendAmountUSD} ${params.tokenIn}\n` +
      `   Protocol:    ${params.protocol}\n` +
      `   Current ETH: $${currentETHPrice}\n\n` +
      `   Reply "approve" to continue.`
    );
    return; // Pause — wait for explicit user approval
  }

  // ── 4. Launch browser and place order ────────────────────────────────────
  console.log(`🚀 Placing limit buy: ETH @ $${params.limitPrice} via ${params.protocol}`);

  const browser = await chromium.launchPersistentContext(
    config.browserProfile,
    {
      headless: false,          // visible so MetaMask popups work
      args: [
        `--disable-extensions-except=${config.metamaskPath}`,
        `--load-extension=${config.metamaskPath}`,
      ],
    }
  );

  try {
    const page = await browser.newPage();

    if (params.protocol === 'cowswap') {
      await placeCowSwapLimitOrder(page, params, spendAmountUSD, logger);
    } else if (params.protocol === '1inch') {
      await place1inchLimitOrder(page, params, spendAmountUSD, logger);
    } else {
      throw new Error(`Protocol "${params.protocol}" UI automation not yet implemented`);
    }

  } finally {
    await browser.close();
  }
}

