// Quick pre-flight before touching the browser
async function preflightCheck(spendUSD: number, config: Config): Promise<void> {
  const guard = new TransactionGuard(config);

  // 1. Per-transaction limit
  const perTxCap = parseFloat(config.constraints.spendLimit.perTx) / 1e6;
  if (spendUSD > perTxCap) {
    throw new Error(
      `❌ Per-tx limit exceeded: $${spendUSD} > $${perTxCap} cap.\n` +
      `   Raise perTx in permissions.json or reduce order size.`
    );
  }

  // 2. Daily rolling limit
  const dailyCap   = parseFloat(config.constraints.spendLimit.daily) / 1e6;
  const spentToday = await getSpentToday(); // reads from logger
  if (spentToday + spendUSD > dailyCap) {
    throw new Error(
      `❌ Daily limit would be exceeded: ` +
      `$${spentToday} spent + $${spendUSD} new = $${spentToday + spendUSD} > $${dailyCap} cap.`
    );
  }

  // 3. Approval threshold
  const approvalThreshold = config.constraints.requireApproval?.above ?? Infinity;
  if (spendUSD > approvalThreshold) {
    // Logged and surfaced to user — execution halts here
    throw new ApprovalRequiredError({
      action:      'limit-buy',
      tokenIn:     'USDC',
      tokenOut:    'ETH',
      amountIn:    spendUSD,
      limitPrice:  2750,
      ethAmount:   1,
      protocol:    'cowswap',
    });
  }

  console.log(`✅ Constraints passed — $${spendUSD} within all limits`);
}
