    const netWorth = document.querySelector('[data-cy="net-worth"]')?.textContent;
    const totalBorrowed = document.querySelector('[data-cy="total-borrow"]')?.textContent;
    const totalCollateral = document.querySelector('[data-cy="total-collateral"]')?.textContent;

    return { healthFactor, netWorth, totalBorrowed, totalCollateral };
  });

  return positionData;
}

