```typescript
// src/guard.ts
import { estimateUSD } from './price';

export async function checkGuard(intent: TransactionIntent, config: Config): Promise<GuardResult> {
  const checks = [];

  // ── 1. Chain allowlist ──────────────────────────────────────────────
  if (!config.permissions.constraints.allowedChains.includes(intent.chainId)) {
    return {
      allowed: false,
      reason: `Chain ${intent.chainId} not in allowlist: ${config.permissions.constraints.allowedChains}`
    };
  }
  checks.push('✅ Chain 1 (Ethereum mainnet) is allowed');

  // ── 2. Protocol allowlist ───────────────────────────────────────────
  // Uniswap Universal Router on mainnet
  const UNISWAP_UNIVERSAL_ROUTER = '0x3fC91A3afd70395Cd496C647d5a6CC9D4B2b7FAD';
  if (!config.permissions.constraints.allowedProtocols.includes(intent.to.toLowerCase())) {
    return {
      allowed: false,
      reason: `Protocol ${intent.to} not in allowlist`
    };
  }
  checks.push('✅ Uniswap Universal Router is in allowlist');

  // ── 3. Per-transaction spend limit ─────────────────────────────────
  const usdValue = await estimateUSD(intent);  // $50.00
  const perTxLimit = Number(config.permissions.constraints.spendLimit.perTx) / 1e6; // $10 → need to check

  if (usdValue > perTxLimit) {
    // Check if approval threshold applies instead of hard block
    if (usdValue <= config.permissions.constraints.requireApproval?.above) {
      return {
        allowed: true,
        requiresApproval: true,
        reason: `$${usdValue} exceeds per-tx limit $${perTxLimit} — requires explicit approval`
      };
    }
    return {
      allowed: false,
      reason: `$${usdValue} exceeds per-tx hard limit of $${perTxLimit}`
    };
  }
  checks.push(`✅ Per-tx spend $50.00 within limit`);

  // ── 4. Daily spend limit ────────────────────────────────────────────
  const dailySpent = await getDailySpent();  // from logs
  const dailyLimit = Number(config.permissions.constraints.spendLimit.daily) / 1e6;

  if (dailySpent + usdValue > dailyLimit) {
    return {
      allowed: false,
      reason: `Would exceed daily limit: $${dailySpent} spent + $${usdValue} = $${dailySpent + usdValue} > $${dailyLimit}`
    };
  }
  checks.push(`✅ Daily spend $0 + $50 = $50 within $${dailyLimit} limit`);

  // ── 5. Blocked methods ──────────────────────────────────────────────
  const methodSelector = intent.data.slice(0, 10);
  if (config.permissions.constraints.blockedMethods?.includes(methodSelector)) {
    return { allowed: false, reason: `Method ${methodSelector} is blocked` };
  }
  checks.push('✅ Method selector not blocked');

  return { allowed: true, checks };
}
```

**Guard Output:**
```
✅ Chain 1 (Ethereum mainnet) is allowed
✅ Uniswap Universal Router is in allowlist
✅ Per-tx spend $50.00 within limit ($50 limit)
✅ Daily spend $0 + $50 = $50 within $50 limit
✅ Method selector not blocked

Guard result: ALLOWED
```

> ⚠️ **Note:** $50 is exactly at the per-tx limit. If your `perTx` is set lower (e.g., $10), the guard would pause and request your approval before continuing.

