// src/guard.ts
import { ethers } from 'ethers';
import { getUSDPrice } from './price';
import { loadPermissions } from './config';
import { loadDailySpend, recordSpend } from './logger';

export interface GuardResult {
  allowed: boolean;
  reason?: string;
  requiresApproval?: boolean;
}

export async function checkSwap(params: {
  tokenIn:  string;   // symbol
  amountIn: string;   // human-readable
  chainId:  number;
  routerAddress: string;
}): Promise<GuardResult> {
  const perms = loadPermissions();
  const c = perms.constraints;

  // 0. Revocation check
  if (c.revoked) {
    return { allowed: false, reason: 'Agent wallet has been revoked.' };
  }

  // 1. Chain allowlist
  if (!c.allowedChains.includes(params.chainId)) {
    return { allowed: false, reason: `Chain ${params.chainId} is not whitelisted.` };
  }

  // 2. Protocol allowlist
  const routerLower = params.routerAddress.toLowerCase();
  if (!c.allowedProtocols.map(a => a.toLowerCase()).includes(routerLower)) {
    return { allowed: false, reason: `Router ${params.routerAddress} is not whitelisted.` };
  }

  // 3. USD value of the swap
  const price   = await getUSDPrice(params.tokenIn);          // e.g. USDC ≈ $1.00
  const usdValue = price * parseFloat(params.amountIn);       // 1.00 * 100 = $100
  const usdRaw   = BigInt(Math.round(usdValue * 1_000_000));  // 100_000_000 (6 dec)

  // 4. Per-tx limit
  if (usdRaw > BigInt(c.spendLimit.perTx)) {
    return {
      allowed: false,
      reason: `$${usdValue} exceeds per-tx limit of $${Number(c.spendLimit.perTx) / 1e6}.`,
    };
  }

  // 5. Daily limit
  const dailySpent = await loadDailySpend();                  // from log file
  if (dailySpent + usdRaw > BigInt(c.spendLimit.daily)) {
    return {
      allowed: false,
      reason: `Would exceed daily limit. Spent today: $${Number(dailySpent) / 1e6}.`,
    };
  }

  // 6. Approval threshold
  if (usdRaw >= BigInt(c.requireApproval.above)) {
    return {
      allowed: true,
      requiresApproval: true,
      reason: `$${usdValue} meets or exceeds approval threshold of $${Number(c.requireApproval.above) / 1e6}. Awaiting human confirmation.`,
    };
  }

  return { allowed: true };
}
```

