```typescript
// src/guard.ts - Permission check
import { readFileSync } from 'fs';
import { estimateUSDValue } from './price';

interface Permissions {
  constraints: {
    spendLimit: { daily: string; perTx: string };
    allowedChains: number[];
    allowedProtocols: string[];
    blockedMethods: string[];
    requireApproval: { above: string };
    revoked?: boolean;
  };
}

async function checkSwapPermission(
  amountETH: number,
  chainId: number
): Promise<{ allowed: boolean; reason?: string; requiresApproval?: boolean }> {

  const permissions: Permissions = JSON.parse(
    readFileSync('./permissions.json', 'utf-8')
  );
  const { constraints } = permissions;

  // 1. Check if revoked
  if (constraints.revoked) {
    return { allowed: false, reason: 'Agent wallet is revoked' };
  }

  // 2. Check chain allowlist
  if (!constraints.allowedChains.includes(chainId)) {
    return { allowed: false, reason: `Chain ${chainId} not in allowlist` };
  }

  // 3. Estimate USD value (0.1 ETH @ ~$3,200 = ~$320)
  const usdValue = await estimateUSDValue('ETH', amountETH);
  const perTxLimit = parseInt(constraints.spendLimit.perTx) / 1e6; // $10

  if (usdValue > perTxLimit) {
    return {
      allowed: false,
      reason: `$${usdValue} exceeds per-tx limit of $${perTxLimit}`
    };
  }

  // 4. Check if approval required
  const approvalThreshold = parseInt(constraints.requireApproval.above) / 1e6;
  if (usdValue > approvalThreshold) {
    return { allowed: true, requiresApproval: true };
  }

  return { allowed: true };
}
```

