// src/wallet.ts - MetaMask swap execution
import { chromium, BrowserContext, Page } from 'playwright';
import { logger } from './logger';

const UNISWAP_URL = 'https://app.uniswap.org/swap';
const METAMASK_EXTENSION_ID = 'nkbihfbeogaeaoehlefnkodbefgpgknn';

async function executeSwap(
  context: BrowserContext,
  amountETH: string,        // "0.1"
  tokenOut: string          // "USDC"
): Promise<{ txHash: string }> {

  const page = await context.newPage();

  // ── 1. Navigate to Uniswap ──────────────────────────────────────────
  await page.goto(UNISWAP_URL);
  await page.waitForLoadState('networkidle');

  // ── 2. Connect wallet ───────────────────────────────────────────────
  await page.click('[data-testid="navbar-connect-wallet"]');
  await page.click('text=MetaMask');

  // Handle MetaMask connection popup
  const mmPage = await waitForMetaMaskPopup(context);
  await mmPage.click('[data-testid="page-container-footer-next"]'); // Connect
  await mmPage.click('[data-testid="page-container-footer-next"]'); // Confirm

  // ── 3. Set swap inputs ──────────────────────────────────────────────
  // Input token: ETH (already default)
  await page.fill('[data-testid="swap-currency-input"] input', amountETH);

  // Output token: USDC
  await page.click('[data-testid="swap-currency-output"] [data-testid="token-selector"]');
  await page.fill('[data-testid="token-search-input"]', 'USDC');
  await page.click('[data-testid="token-item-USDC"]');

  // ── 4. Wait for quote ───────────────────────────────────────────────
  await page.waitForSelector('[data-testid="swap-details-header-amount"]', {
    timeout: 10_000
  });

  const quoteText = await page.textContent(
    '[data-testid="swap-details-header-amount"]'
  );
  console.log(`Quote: ${amountETH} ETH → ${quoteText} USDC`);

  // ── 5. Submit swap ──────────────────────────────────────────────────
  await page.click('[data-testid="swap-button"]');
  await page.click('[data-testid="confirm-swap-button"]');

  // ── 6. Approve in MetaMask ──────────────────────────────────────────
  const txPopup = await waitForMetaMaskPopup(context);

  // Read transaction details before confirming
  const txDetails = await extractTxDetails(txPopup);
  logger.logIntent(txDetails);

  await txPopup.click('[data-testid="page-container-footer-next"]'); // Confirm tx

  // ── 7. Wait for confirmation ────────────────────────────────────────
  const txHash = await waitForTxHash(page);
  logger.logOutcome(txHash, 'confirmed');

  return { txHash };
}

async function waitForMetaMaskPopup(context: BrowserContext): Promise<Page> {
  return new Promise((resolve) => {
    context.on('page', (page) => {
      if (page.url().includes(METAMASK_EXTENSION_ID)) {
        resolve(page);
      }
    });
  });
}

async function extractTxDetails(mmPage: Page) {
  const to      = await mmPage.textContent('[data-testid="sender-to-address"]');
  const value   = await mmPage.textContent('[data-testid="confirm-page-total-amount"]');
  const gasEst  = await mmPage.textContent('[data-testid="confirm-page-gas-fee"]');
  return { to, value, gasEst };
}
