// src/guard.ts
import { Permissions, TransactionIntent, GuardResult } from './types';
import { getSpentToday } from './logger';
import { estimateUsdValue } from './price';

export async function checkPermissions(
  intent: TransactionIntent,
  permissions: Permissions
): Promise<GuardResult> {
  const { constraints } = permissions;

  // 0. Check if wallet is revoked
  if (permissions.revoked) {
    return { allowed: false, requiresApproval: false, reason: 'Wallet access revoked' };
  }

  // 1. Chain allowlist check
  if (!constraints.allowedChains.includes(intent.chainId)) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Chain ${intent.chainId} not in allowlist: [${constraints.allowedChains.join(', ')}]`
    };
  }

  // 2. Protocol allowlist check
  const toNorm = intent.to.toLowerCase();
  const allowed = constraints.allowedProtocols.map(p => p.toLowerCase());
  if (!allowed.includes(toNorm)) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Protocol ${intent.to} not in allowlist`
    };
  }

  // 3. Blocked method selectors (first 4 bytes of calldata)
  const selector = intent.data.slice(0, 10);
  if (constraints.blockedMethods.includes(selector)) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Method selector ${selector} is blocked`
    };
  }

  // 4. Per-transaction spend limit
  const usdValue = parseFloat(intent.estimatedUsdValue);
  const perTxLimit = parseFloat(constraints.spendLimit.perTx) / 1e6; // convert from 6-decimal
  if (usdValue > perTxLimit) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Transaction value $${usdValue} exceeds per-tx limit $${perTxLimit}`
    };
  }

  // 5. Daily spend limit
  const spentToday = await getSpentToday();
  const dailyLimit = parseFloat(constraints.spendLimit.daily) / 1e6;
  if (spentToday + usdValue > dailyLimit) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Would exceed daily limit. Spent: $${spentToday}, Limit: $${dailyLimit}`
    };
  }

  // 6. Approval threshold check
  const approvalThreshold = parseFloat(constraints.requireApproval.above);
  if (usdValue > approvalThreshold) {
    return {
      allowed: true,
      requiresApproval: true,
      reason: `Value $${usdValue} exceeds approval threshold $${approvalThreshold} — awaiting user confirmation`
    };
  }

  return { allowed: true, requiresApproval: false };
}
```

