## Step 2: Run the Guard Check

```typescript
// src/guard.ts
import { ethers } from 'ethers';
import { Permissions, TransactionIntent, GuardResult } from './types';

export class TransactionGuard {
  private permissions: Permissions;
  private dailySpent: bigint = 0n;
  private dailyResetAt: number = Date.now() + 86_400_000;

  constructor(permissions: Permissions) {
    this.permissions = permissions;
  }

  check(intent: TransactionIntent): GuardResult {
    const c = this.permissions.constraints;

    // ── 0. Global kill-switch ──────────────────────────────────────────────
    if (this.permissions.revoked) {
      return { allowed: false, reason: 'Wallet permissions have been revoked.' };
    }

    // ── 1. Chain allowlist ─────────────────────────────────────────────────
    if (!c.allowedChains.includes(intent.chainId)) {
      return {
        allowed: false,
        reason: `Chain ${intent.chainId} is not in the allowlist: [${c.allowedChains.join(', ')}]`,
      };
    }

    // ── 2. Protocol allowlist ──────────────────────────────────────────────
    const toChecksummed = ethers.getAddress(intent.to);
    const allowed = c.allowedProtocols.map(a => ethers.getAddress(a));
    if (!allowed.includes(toChecksummed)) {
      return {
        allowed: false,
        reason: `Contract ${toChecksummed} is not in the protocol allowlist.`,
      };
    }

    // ── 3. Blocked method selectors ────────────────────────────────────────
    if (intent.data.length >= 10) {
      const selector = intent.data.slice(0, 10).toLowerCase();
      if (c.blockedMethods.map(m => m.toLowerCase()).includes(selector)) {
        return {
          allowed: false,
          reason: `Method selector ${selector} is explicitly blocked.`,
        };
      }
    }

    // ── 4. Per-transaction spend limit ─────────────────────────────────────
    const usdValue = BigInt(intent.estimatedUsdValue);
    const perTxLimit = BigInt(c.spendLimit.perTx);
    if (usdValue > perTxLimit) {
      return {
        allowed: false,
        reason: `Transaction value $${fmt(usdValue)} exceeds per-tx limit $${fmt(perTxLimit)}.`,
      };
    }

    // ── 5. Daily spend limit ───────────────────────────────────────────────
    this.maybeResetDaily();
    const dailyLimit = BigInt(c.spendLimit.daily);
    if (this.dailySpent + usdValue > dailyLimit) {
      return {
        allowed: false,
        reason: `Would exceed daily limit. Spent $${fmt(this.dailySpent)}, limit $${fmt(dailyLimit)}.`,
      };
    }

    // ── 6. Approval threshold ──────────────────────────────────────────────
    const approvalThreshold = BigInt(c.requireApproval.above);
    if (usdValue > approvalThreshold) {
      return {
        allowed: true,
        requiresApproval: true,
      };
    }

    return { allowed: true };
  }

  recordSpend(usdValue: string) {
    this.maybeResetDaily();
    this.dailySpent += BigInt(usdValue);
  }

  private maybeResetDaily() {
    if (Date.now() > this.dailyResetAt) {
      this.dailySpent = 0n;
      this.dailyResetAt = Date.now() + 86_400_000;
    }
  }
}

// Format 6-decimal USD value as human-readable string
function fmt(v: bigint): string {
  const s = v.toString().padStart(7, '0');
  return `${s.slice(0, -6)}.${s.slice(-6)}`;
}
```

