```typescript
// src/price.ts
export async function estimateUsdValue(
  tokenSymbol: string,
  amount: string,   // human-readable (e.g. "1.0")
  decimals: number
): Promise<string> {
  // Fetch ETH price from a public oracle endpoint
  const res = await fetch(
    'https://api.coingecko.com/api/v3/simple/price?ids=ethereum&vs_currencies=usd'
  );
  const json = await res.json() as { ethereum: { usd: number } };
  const ethPrice = json.ethereum.usd;          // e.g. 3200

  const usd = parseFloat(amount) * ethPrice;   // 1 * 3200 = 3200
  // Return as 6-decimal integer string
  return Math.round(usd * 1_000_000).toString();
}
